    el2.appendChild(buttonsRow);
    widgetButtons = [];
    for (let i = 0; i < MAX_BUTTONS; i++) {
      const btn = createButton2();
      buttonsRow.appendChild(btn);
      widgetButtons.push(btn);
    }
    installDragHandlers(el2);
    document.body.appendChild(el2);
    widget = el2;
    positioned = false;
    updateButtons();
